validate.custom:
valid = validateIdentification(input);

function validateIdentification(identification) {
    let status = false;
    let id = identification.toString().trim();

    if (id.length >= 9) {
        let sum = 0;
        let calculation = 0;
        let digit = '';
        let firstPart = id.substring(0, 8);
        let secondPart = id.substring(8, 9);

        for (let i = firstPart.length - 1; i >= 0; i--) {
            let start = i;
            let end = i + 1;

            if (end <= firstPart.length) {
                let j = i + 1;
                sum += ((parseInt(firstPart.substring(start, end))) * (firstPart.length - j + 2));
            }
        }
        calculation += 11 - MOD(sum, 11);

        if (calculation == 11) {
            digit = "0";
        } else if (calculation == 10) {
            digit = "K";
        } else {
            digit = calculation.toString();
        }

        if (digit == secondPart) {
            status = true;
        } else {
            status = false;
        }
    }

    return status;
}

function MOD(m, n) {
    if (n === 0) {
        return m;
    }

    return (m - n * Math.floor(m / n));
}

