      try {
        // app.ws envuelve en { ok, status, data, headers } — la respuesta real esta en .data
        let apiResponse = resultDom.data;

        if (apiResponse && apiResponse.status === true) {
          let titular = "";
          if (resultNis && resultNis.code === 200 && resultNis.data && resultNis.data.NOMBRE) {
            titular = resultNis.data.NOMBRE.replace(/[^\w\sáéíóúÁÉÍÓÚñÑüÜ.#\-\/]/g, "");
          }

          const resultado = {
            titular: titular,
            dpiList: apiResponse.data.dpiList || [],
            identificadorRecordCount: apiResponse.data.identificadorRecordCount || 0
          };

          // Guardar el JSON en resultadoNIS usando Formio
          if (typeof form !== "undefined" && typeof form.getComponent === "function") {
            form.getComponent("resultadoNIS").setValue(JSON.stringify(resultado));
