            document.getElementById("CONT_DATOS_NIS").innerHTML = `
              <div style="background-color: #fff3cd; border: 2px solid #ffc107; border-radius: 8px; padding: 15px; margin-top: 10px;">
                <p style="color: #856404; font-weight: bold; margin: 0;">⚠ ${mensaje}</p>
                ${titular ? `<p style="color: #856404; margin: 8px 0 0 0; font-size: 13px;">Titular: <strong>${titular}</strong></p>` : ""}
                ${dpiListHtml}
              </div>
            `;
          } else {
            document.getElementById("CONT_DATOS_NIS").innerHTML = "";
          }
        }

        if (resultNis && resultNis.code === 200 && resultNis.data) {
          let direccion = resultNis.data.DIRECCION || "";
          direccion = direccion.replace(/[^\w\sáéíóúÁÉÍÓÚñÑüÜ.#\-\/]/g, "");

          // Setear DIRECCION_DOMICILIO usando Formio
          if (typeof form !== "undefined" && typeof form.getComponent === "function") {
            form.getComponent("DIRECCION_DOMICILIO").setValue(direccion);
            console.log("Campo DIRECCION_DOMICILIO seteado con form.getComponent:", direccion);
          } else {
            // Fallback por si no existe form
            let input = document.querySelector('input[name="data[DIRECCION_DOMICILIO]"]');
            if (input) {
              input.value = direccion;
              input.dispatchEvent(new Event("input", { bubbles: true }));
              input.dispatchEvent(new Event("change", { bubbles: true }));
              console.log("Seteado DIRECCION_DOMICILIO:", input.value);
            }
          }
        }
