var total = 0;
var selectedProducts = []; 
function processSelection(selection, categoryKey) {
    var isCategoryActive = data.TIPO_COMP && data.TIPO_COMP[categoryKey] === true;
    if (!selection || !isCategoryActive) return;
 
    var items = Array.isArray(selection) ? selection : [selection];
 
    items.forEach(function(val) {
        var numericVal = parseInt(val);
        var product = { value: numericVal, price: 0, codProd: "", codCom: "", esTelco: false };
 
        switch (numericVal) {
            case 1: product.price = 535;  product.codProd = "8";  product.codCom = "C5"; break;
            case 2: product.price = 675;  product.codProd = "9";  product.codCom = "C8"; break;
            case 3: product.price = 250;  product.codProd = "20"; product.codCom = "21"; break;
            case 4: product.price = 700;  product.codProd = "PQ"; product.codCom = "C4"; break;
            case 5: product.price = 1550; product.codProd = "PG"; product.codCom = "C3"; break;
            case 6: product.price = 1500; product.codProd = "TB"; product.codCom = "C9"; product.esTelco = true; break;
            case 7: product.price = 1500; product.codProd = "CG"; product.codCom = "2C"; product.esTelco = true; break;
            case 8: product.price = 2040; product.codProd = "TA"; product.codCom = "3C"; product.esTelco = true; break;
            case 9: product.price = 2040; product.codProd = "CA"; product.codCom = "1C"; product.esTelco = true; break;
        }
 
        if (product.codProd === "TB") product.COMP_TELCO = 6;
        if (product.codProd === "CG") product.COMP_TELCO = 5;
        if (product.codProd === "TA") product.COMP_TELCO = 8;
        if (product.codProd === "CA") product.COMP_TELCO = 7;
 
        if (product.price > 0) {
            total += product.price;
            selectedProducts.push(product);
        }
    });
}
 
