const TOTAL_COMPLEMENTARIOS = row.TOTAL_COMPLEMENTARIOS || 0; 
const AGREGAR_SEGURO = row.AGREGAR_SEGURO;
const FRECUENCIA_DE_PAGO = row.FRECUENCIA_DE_PAGO;
const EXCEDENTE_FAMILIAR = row.excedenteFamiliar || 0;

if (MONTO_SOLICITADO <= 0 || CANTIDAD_DE_CUOTAS <= 0 || FRECUENCIA_DE_PAGO <= 0) {
    instance.setCustomValidity("Faltan parametros para cotizar el producto");
    return;
}

let FRECUENCIA_DIAS = 0;
const SEGURO_BASE = 14.75;
let CUOTA_COMPLEMENTARIOS = 0;

if (FRECUENCIA_DE_PAGO === 1) {
  FRECUENCIA_DIAS = 30.0;
} else if (FRECUENCIA_DE_PAGO === 21) {
  FRECUENCIA_DIAS = 14.0;
}

if (TOTAL_COMPLEMENTARIOS > 0 && CANTIDAD_DE_CUOTAS > 0) {
    CUOTA_COMPLEMENTARIOS = TOTAL_COMPLEMENTARIOS / CANTIDAD_DE_CUOTAS;
}

const TASA_PERIODICA = TASA_RAIZ / 100.0 / (360.0 / FRECUENCIA_DIAS);
const POTENCIA = Math.pow(1.0 + TASA_PERIODICA, CANTIDAD_DE_CUOTAS);
const CUOTA_AMORTIZACION = (MONTO_SOLICITADO * (POTENCIA * TASA_PERIODICA)) / (POTENCIA - 1);

let CUOTA_FINAL = 0;
if (AGREGAR_SEGURO === 0 || AGREGAR_SEGURO === '0') {
  CUOTA_FINAL = Math.ceil(CUOTA_AMORTIZACION + CUOTA_COMPLEMENTARIOS);
} else {
  CUOTA_FINAL = Math.ceil(CUOTA_AMORTIZACION + SEGURO_BASE + CUOTA_COMPLEMENTARIOS);
}

let porcentajeExcedente = 0;
if (parseFloat(EXCEDENTE_FAMILIAR) > 0) {
    porcentajeExcedente = (CUOTA_FINAL * 2 / EXCEDENTE_FAMILIAR) * 100;
}

form.getComponent("CUOTA_1").setValue(CUOTA_FINAL);
form.getComponent("cuotaCreditosExcedenteFamiliar").setValue(porcentajeExcedente.toFixed(2));

console.log("Calculo Unificado Finalizado", { Cuota: CUOTA_FINAL, ExcedentePct: porcentajeExcedente });

