wrapper.appendChild(overlay);
container.appendChild(wrapper);

var fitScale = wrapperWidth / iframeWidth;

function applyZoom(s) {
  currentScale = Math.min(Math.max(s, 0.2), 3);
  overlay.style.transform = 'scale(' + currentScale + ')';
  overlay.style.width = iframeWidth + 'px';
  overlay.style.height = iframeHeight + 'px';
  }

applyZoom(fitScale);

function getDist(t) {
  var dx = t[0].clientX - t[1].clientX;
  var dy = t[0].clientY - t[1].clientY;
  return Math.sqrt(dx * dx + dy * dy);
}

wrapper.addEventListener('touchstart', function(e) {
  if (e.touches.length === 2) {
    e.preventDefault();
    lastDist = getDist(e.touches);
  }
}, { passive: false });

wrapper.addEventListener('touchmove', function(e) {
  if (e.touches.length === 2) {
    e.preventDefault();
    var dist = getDist(e.touches);
    if (lastDist > 0) {
      var delta = dist / lastDist;
      applyZoom(currentScale * delta);
    }
    lastDist = dist;
  }
}, { passive: false });

wrapper.addEventListener('touchend', function(e) {
  lastDist = 0;
});

wrapper.addEventListener('dblclick', function() {
  applyZoom(fitScale);
});

